  void attach() {
    WidgetsBinding.instance.addObserver(this);
  }

  void tap(String target, {Map<String, Object?>? meta}) {
    ProdLog.i(tag, 'tap:$target', extras: meta);
  }

  void action(String name, {Map<String, Object?>? meta}) {
    ProdLog.i(tag, 'action:$name', extras: meta);
  }

  void screen(String name, {Map<String, Object?>? meta}) {
    ProdLog.i(tag, 'screen:$name', extras: meta);
  }

  @override
  void didPush(Route<dynamic> route, Route<dynamic>? previousRoute) {
    ProdLog.i(tag, 'nav:push', extras: {'to': route.settings.name, 'from': previousRoute?.settings.name});
    super.didPush(route, previousRoute);
  }

  @override
  void didPop(Route<dynamic> route, Route<dynamic>? previousRoute) {
    ProdLog.i(tag, 'nav:pop', extras: {'from': route.settings.name, 'to': previousRoute?.settings.name});
    super.didPop(route, previousRoute);
  }

  @override
  void didReplace({Route<dynamic>? newRoute, Route<dynamic>? oldRoute}) {
    ProdLog.i(tag, 'nav:replace', extras: {'new': newRoute?.settings.name, 'old': oldRoute?.settings.name});
    super.didReplace(newRoute: newRoute, oldRoute: oldRoute);
  }

  @override
  void didRemove(Route<dynamic> route, Route<dynamic>? previousRoute) {
    ProdLog.i(tag, 'nav:remove', extras: {'route': route.settings.name, 'previous': previousRoute?.settings.name});
    super.didRemove(route, previousRoute);
  }

  @override
  void didChangeAppLifecycleState(AppLifecycleState state) {
    ProdLog.i(tag, 'lifecycle:$state');
    super.didChangeAppLifecycleState(state);
  }

  void timed(String name, Duration duration, {Map<String, Object?>? meta}) {
    ProdLog.i(tag, 'timer:start:$name', extras: {'durationMs': duration.inMilliseconds, ...?meta});
    final t = Timer(duration, () {
      ProdLog.i(tag, 'timer:fire:$name', extras: meta);
    });
    _timers.add(t);
  }
