class AppHealth {
  AppHealth._();

  static void installGlobalErrorHandlers({String tag = 'HEALTH'}) {
    FlutterError.onError = (FlutterErrorDetails details) {
      ProdLog.e(tag, 'flutter_error', error: details.exception, st: details.stack, extras: {
        'library': details.library,
        'context': details.context?.toDescription(),
        'information': details.informationCollector?.call().map((n) => n.toString()).toList(),
      });
    };

    PlatformDispatcher.instance.onError = (error, stack) {
      ProdLog.e(tag, 'platform_error', error: error, st: stack);
      return true;
    };

    Isolate.current.addErrorListener(RawReceivePort((dynamic pair) {
      try {
        final List<dynamic> errorAndStacktrace = pair as List<dynamic>;
        final err = errorAndStacktrace[0];
        final st = StackTrace.fromString(errorAndStacktrace[1].toString());
        ProdLog.e(tag, 'isolate_error', error: err, st: st);
      } catch (e, st) {
        ProdLog.e(tag, 'isolate_error_listener_failed', error: e, st: st);
      }
    }).sendPort);
  }
}

class LoggingTapRegion extends StatelessWidget {
  const LoggingTapRegion({
    super.key,
    required this.child,
    required this.interactions,
    this.name = 'region',
    this.meta,
  });

  final Widget child;
  final UserInteractionLogger interactions;
  final String name;
  final Map<String, Object?>? meta;

  @override
  Widget build(BuildContext context) {
    return GestureDetector(
      behavior: HitTestBehavior.translucent,
      onTap: () => interactions.tap(name, meta: meta),
      onLongPress: () => interactions.action('long_press:$name', meta: meta),
      child: child,
    );
  }
}